-- Test Users for GUTMANN System
-- Passwords are bcrypt hashes (12 rounds) generated by scripts/generate-bcrypt-hashes.js
-- Run this in Supabase SQL Editor after the schema migrations.
--
-- Password legend:
--   ceo@gutmann.com        -> Admin@12345
--   sales@gutmann.com      -> Sales@12345
--   qc@gutmann.com         -> Qc@12345
--   technical@gutmann.com  -> Tech@12345
--   estimation@gutmann.com -> Est@12345
--
-- Regenerate hashes at any time:
--   cd <repo-root> && node scripts/generate-bcrypt-hashes.js

-- pgcrypto provides gen_random_uuid(); safe to run even if already enabled.
CREATE EXTENSION IF NOT EXISTS pgcrypto;

-- CEO
INSERT INTO public.users (id, email, password_hash, name, role, is_active, created_at, updated_at)
SELECT
  gen_random_uuid(),
  'ceo@gutmann.com',
  '$2a$12$hIEEFP/ftW2ySV/.TwsCj.GPkqrnJFA57la2LAN61m7307/cbQsxa',
  'Ahmad Al-Rashid',
  'ceo',
  true,
  NOW(),
  NOW()
WHERE NOT EXISTS (
  SELECT 1 FROM public.users WHERE email = 'ceo@gutmann.com'
);

