-- Verify inserted rows
SELECT id, email, name, role, is_active, created_at
FROM public.users
WHERE email IN (
  'ceo@gutmann.com',
  'sales@gutmann.com',
  'qc@gutmann.com',
  'technical@gutmann.com',
  'estimation@gutmann.com'
)
ORDER BY
  CASE role
    WHEN 'ceo'         THEN 1
    WHEN 'salesperson' THEN 2
    WHEN 'qc'          THEN 3
    WHEN 'technical'   THEN 4
    WHEN 'estimation'  THEN 5
  END;
